// // This module performs an 8-bit to 4-bit sign extension instead of zero extension
module zero_extend_4to8(
    input               clk     ,
    input               rst_n   ,
    input       [3:0]   data_in ,

    output  reg [7:0]   data_out
);

    // 4-bit zero extension to 8-bit
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            data_out <= 0;
        end else begin
            data_out <= {4'b0000, data_in};
        end
    end

endmodule
